import{_ as o,c as t,o as r,ae as i}from"./chunks/framework.CkyPvWOg.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"javascript/浏览器原理.md","filePath":"javascript/浏览器原理.md","lastUpdated":1773308029000}'),a={name:"javascript/浏览器原理.md"};function s(e,l,n,g,d,S){return r(),t("div",null,[...l[0]||(l[0]=[i('<h3 id="浏览器" tabindex="-1">浏览器 <a class="header-anchor" href="#浏览器" aria-label="Permalink to &quot;浏览器&quot;">​</a></h3><ul><li>浏览器是多进程的</li></ul><h3 id="一-浏览器内核" tabindex="-1">一. 浏览器内核 <a class="header-anchor" href="#一-浏览器内核" aria-label="Permalink to &quot;一. 浏览器内核&quot;">​</a></h3><ol><li>Blink内核</li></ol><ul><li><strong>代表浏览器</strong>： 谷歌，Edge，Opera</li><li><strong>特点</strong>: 由Google开发，基于WebKit分支而来，注重性能和现代网页支持，采用多进程架构提升稳定性和安全性</li></ul><ol start="2"><li>WebKit内核</li></ol><ul><li><strong>代表浏览器</strong>： Apple Safar</li><li><strong>特点</strong>‌：由苹果公司开发，开源且轻量化，在移动设备上表现优异，深度优化于Apple生态系统</li></ul><ol start="3"><li>Gecko内核</li></ol><ul><li><strong>代表浏览器</strong>： Mozilla Firefox(火狐)</li><li><strong>特点</strong>‌：由Mozilla开发，开源且跨平台，强调对W3C标准的兼容性和强大的扩展支持</li></ul><ol start="4"><li>Trident内核</li></ol><ul><li><strong>代表浏览器</strong>‌：Internet Explorer（已逐步被Edge替代）‌</li><li><strong>特点</strong>‌：由微软开发，曾因市场份额高但更新滞后导致兼容性问题，现已不再积极维护‌</li></ul><h3 id="二-页面渲染流程" tabindex="-1">二. 页面渲染流程 <a class="header-anchor" href="#二-页面渲染流程" aria-label="Permalink to &quot;二. 页面渲染流程&quot;">​</a></h3><p>从输入URL到页面展示，主要分为以下步骤‌</p><ol><li><strong>导航</strong>‌：用户输入URL后，浏览器发起DNS查询获取服务器IP，建立TCP连接</li><li><strong>资源加载</strong>‌：通过HTTP/HTTPS协议请求HTML、CSS、JS等资源</li><li><strong>解析与渲染</strong>‌： <ul><li>解析HTML生成DOM树；解析CSS生成CSSOM树；合并为渲染树</li><li>计算布局<code>（Layout）</code>和绘制<code>（Paint）</code>，最终由<code>GPU</code>合成显示</li></ul></li></ol><h3 id="三-核心渲染流程" tabindex="-1">三. 核心渲染流程 <a class="header-anchor" href="#三-核心渲染流程" aria-label="Permalink to &quot;三. 核心渲染流程&quot;">​</a></h3><ol><li><strong>解析HTML生成DOM树</strong>:浏览器将HTML字符串解析为文档对象模型（DOM树），表示页面的结构‌</li><li><strong>解析CSS生成CSSOM树</strong>‌：同时解析CSS样式，构建CSS对象模型（CSSOM树），表示页面的样式规则‌</li><li><strong>构建渲染树</strong>‌：将DOM树和CSSOM树合并，生成渲染树（Render Tree），只包含可见节点及其计算后的样式‌</li><li><strong>‌布局计算</strong>‌：计算渲染树中每个节点的几何信息（如位置、大小），确定页面布局‌</li><li><strong>‌绘制</strong>‌：将布局结果转换为屏幕上的像素信息，完成页面绘制‌</li></ol><h3 id="四-资源间的相互影响" tabindex="-1">四. 资源间的相互影响 <a class="header-anchor" href="#四-资源间的相互影响" aria-label="Permalink to &quot;四. 资源间的相互影响&quot;">​</a></h3><ul><li><p><strong>CSS与HTML</strong>‌: CSS解析会<strong>阻塞</strong>DOM树的构建,因为渲染树需要cssom来计算样式，浏览器会通过预加载扫描器提前请求CSS资源以减少阻塞‌</p></li><li><p><strong>javaScript与HTML/CSS</strong>： javascript脚本会<strong>阻塞</strong>HTML解析，直到脚本执行完成。同时，js脚本可能操作dom或修改样式触发<code>重排</code>和<code>重绘</code>，影响性能</p></li><li><p><strong>图片等资源</strong>: 非阻塞资源（如图片）的加载不会阻塞HTML解析，但可能影响页面布局和绘制时机‌</p></li></ul><h3 id="五-详细阶段解析" tabindex="-1">五.详细阶段解析 <a class="header-anchor" href="#五-详细阶段解析" aria-label="Permalink to &quot;五.详细阶段解析&quot;">​</a></h3><ol><li><strong>DOM树构建</strong></li></ol><ul><li>HTML解析器将HTML字符串转换为DOM节点，形成树状结构‌.此阶段会处理内联样式和外部CSS的预加载‌</li></ul><ol start="2"><li><strong>CSSOM树构建</strong></li></ol><ul><li>CSS解析器将CSS规则转换为样式映射，构建CSSOM树‌.样式会进行标准化处理（如<code>color: blue</code>转换为<code>rgb(0,0,255)</code>）</li></ul><ol start="3"><li><strong>渲染树构建</strong></li></ol><ul><li>渲染树结合<strong>DOM树和CSSOM树</strong>，<strong>仅包含可见节点</strong>（如<code>display: none</code>的元素不包含在内）‌.此阶段会应用计算后的样式到对应元素‌</li></ul><ol start="4"><li><strong>布局计算</strong></li></ol><ul><li>浏览器遍历渲染树，计算每个节点的位置、大小等几何信息，确定页面布局‌。此过程可能因DOM或CSSOM的修改而<strong>重复执行‌</strong></li></ul><ol start="5"><li><strong>绘制与优化</strong></li></ol><ul><li>布局完成后，浏览器将渲染树转换为像素信息，通过分层、光栅化等步骤绘制到屏幕‌。优化手段包括减少重排、使用硬件加速等‌</li></ul><h3 id="性能优化建议" tabindex="-1">性能优化建议 <a class="header-anchor" href="#性能优化建议" aria-label="Permalink to &quot;性能优化建议&quot;">​</a></h3><ul><li><strong>减少重排</strong>‌：避免频繁修改DOM或样式，使用transform代替top/left等布局属性‌</li><li><strong>异步加载资源</strong>‌：将非关键CSS/JS标记为async或defer，减少阻塞‌</li><li><strong>预加载关键资源</strong>‌：利用<link rel="preload">提前加载重要资源‌</li></ul>',31)])])}const h=o(a,[["render",s]]);export{u as __pageData,h as default};
